import {
 getPatients,
 addPatient,
 getAppointments,
 addAppointment
} from "../api";


import Prescription from "./Prescription";


export default function Dashboard() {
 const [page, setPage] = useState("dashboard");


 const [patients, setPatients] = useState([]);
 const [appointments, setAppointments] = useState([]);


 const [patientForm, setPatientForm] = useState({
   name: "",
   phone: "",
   age: ""
 });


 const [appointmentForm, setAppointmentForm] = useState({
   patient_id: "",
   date: ""
 });


 const doctorId = localStorage.getItem("userId");


 // ================= LOAD DATA =================
 useEffect(() => {
   loadData();
 }, []);


 const loadData = async () => {
   const patientsData = await getPatients();
   const appointmentsData = await getAppointments();


   setPatients(patientsData);
   setAppointments(appointmentsData);
 };


 // ================= ADD PATIENT =================
 const handleAddPatient = async () => {
   if (!patientForm.name || !patientForm.phone || !patientForm.age) {
     alert("Please fill all patient fields");
     return;
   }


   await addPatient({
     name: patientForm.name,
     phone: patientForm.phone,
     age: Number(patientForm.age)
   });


   setPatientForm({ name: "", phone: "", age: "" });
   loadData();
 };


 // ================= ADD APPOINTMENT =================
 const handleAddAppointment = async () => {
   if (!appointmentForm.patient_id || !appointmentForm.date) {
     alert("Please select patient and date");
     return;
   }


   await addAppointment({
     patient_id: Number(appointmentForm.patient_id),
     doctor_id: Number(doctorId),
     date: new Date(appointmentForm.date).toISOString()
   });


   setAppointmentForm({ patient_id: "", date: "" });
   loadData();
 };


 return (
   <div style={{ padding: "20px", fontFamily: "Arial" }}>


     {/* ================= NAVIGATION ================= */}
     <div style={{ marginBottom: "20px" }}>
       <button onClick={() => setPage("dashboard")}>
         Dashboard
       </button>


       <button onClick={() => setPage("prescription")}>
         Prescription
       </button>
     </div>


     {/* ================= DASHBOARD PAGE ================= */}
     {page === "dashboard" && (
       <>
         <h2>🦷 Doctor Dashboard</h2>


         {/* ADD PATIENT */}
         <h3>Add Patient</h3>


         <input
           placeholder="Name"
           value={patientForm.name}
           onChange={(e) =>
             setPatientForm({ ...patientForm, name: e.target.value })
           }
         />


         <input
           placeholder="Phone"
           value={patientForm.phone}
           onChange={(e) =>
             setPatientForm({ ...patientForm, phone: e.target.value })
           }
         />


         <input
           placeholder="Age"
           value={patientForm.age}
           onChange={(e) =>
             setPatientForm({ ...patientForm, age: e.target.value })
           }
         />


         <button onClick={handleAddPatient}>
           Add Patient
         </button>


         {/* PATIENT LIST */}
         <h3>Patients</h3>
         {patients.map((p) => (
           <div key={p.id}>
             {p.name} | {p.phone} | Age: {p.age}
           </div>
         ))}


         {/* ADD APPOINTMENT */}
         <h3>Add Appointment</h3>


         <select
           value={appointmentForm.patient_id}
           onChange={(e) =>
             setAppointmentForm({
               ...appointmentForm,
               patient_id: e.target.value
             })
           }
         >
           <option value="">Select Patient</option>


           {patients.map((p) => (
             <option key={p.id} value={p.id}>
               {p.name} - {p.phone}
             </option>
           ))}
         </select>


         <input
           type="datetime-local"
           value={appointmentForm.date}
           onChange={(e) =>
             setAppointmentForm({
               ...appointmentForm,
               date: e.target.value
             })
           }
         />


         <button onClick={handleAddAppointment}>
           Create Appointment
         </button>


         {/* APPOINTMENTS LIST */}
         <h3>Appointments</h3>
         {appointments.map((a) => (
           <div key={a.id}>
             Patient ID: {a.patient_id} |{" "}
             {new Date(a.date).toLocaleString()}
           </div>
         ))}
       </>
     )}


     {/* ================= PRESCRIPTION PAGE ================= */}
     {page === "prescription" && <Prescription />}


   </div>
 );
}
